# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import subprocess
import os
import tempfile
from google.cloud import storage

def convert_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    metadata = blob.metadata or {}
    
    conversion_format = metadata.get('conversion_format', 'png')
    quality = metadata.get('quality', '90')
    resize = metadata.get('resize', '')
    rotate = metadata.get('rotate', '')
    grayscale = metadata.get('grayscale', 'false')
    blur = metadata.get('blur', '')
    brightness = metadata.get('brightness', '')
    contrast = metadata.get('contrast', '')
    output_bucket = metadata.get('output_bucket', bucket_name)
    output_prefix = metadata.get('output_prefix', 'converted/')
    
    base_name = os.path.splitext(os.path.basename(file_name))[0]
    output_file_name = f"{output_prefix}{base_name}.{conversion_format}"
    
    with tempfile.TemporaryDirectory() as temp_dir:
        input_path = os.path.join(temp_dir, os.path.basename(file_name))
        output_path = os.path.join(temp_dir, f"{base_name}.{conversion_format}")
        
        blob.download_to_filename(input_path)
        
        command = ['convert', input_path]
        
        if resize:
            command.extend(['-resize', resize])
        
        if rotate:
            command.extend(['-rotate', rotate])
        
        if grayscale.lower() == 'true':
            command.extend(['-colorspace', 'Gray'])
        
        if blur:
            command.extend(['-blur', blur])
        
        if brightness:
            command.extend(['-brightness-contrast', f"{brightness}x0"])
        
        if contrast:
            current_brightness = brightness if brightness else '0'
            command.extend(['-brightness-contrast', f"{current_brightness}x{contrast}"])
        
        if quality:
            command.extend(['-quality', quality])
        
        command.append(output_path)
        
        result = subprocess.call(command)
        
        if result != 0:
            print(f"ImageMagick conversion failed with return code {result}")
            return
        
        output_bucket_obj = storage_client.bucket(output_bucket)
        output_blob = output_bucket_obj.blob(output_file_name)
        output_blob.upload_from_filename(output_path)
        
        print(f"Successfully converted {file_name} to {output_file_name}")